// Chat.jsx - Complete with all functionalities
import React, { useState, useRef, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import s from './Chat.module.css';

// Language translations
const translations = {
  fr: {
    newChat: 'Nouveau chat',
    today: 'Aujourd\'hui',
    days30: '30 jours',
    settings: 'Paramètres',
    signOut: 'Déconnexion',
    welcomeTitle: 'Bienvenue sur AI Advisor',
    welcomeSub: 'Votre assistant intelligent pour la performance des campagnes, la qualité des utilisateurs et les décisions de croissance.',
    examples: 'Exemples',
    capabilities: 'Capacités',
    limitations: 'Limites',
    example1: 'Quelle campagne a eu le meilleur ROI ces 30 derniers jours ?',
    example2: 'Comparez la rétention entre iOS et Android en Europe',
    example3: 'Quels segments d\'audience chutent après le jour 7 ?',
    cap1: 'Analyser les tendances de performance des campagnes',
    cap2: 'Recommander des réallocations budgétaires',
    cap3: 'Prévoir LTV, rétention et ROAS',
    limit1: 'Les données doivent être disponibles dans votre tableau de bord',
    limit2: 'Les suggestions IA sont basées sur vos données',
    limit3: 'Toujours revoir les recommandations avant application',
    placeholder: 'Demandez tout ce qui concerne vos campagnes, utilisateurs ou performances...',
    hint: 'Entrée pour envoyer · Shift+Entrée pour nouvelle ligne',
    general: 'Général',
    profile: 'Profil',
    data: 'Données',
    about: 'À propos',
    theme: 'Thème',
    light: 'Clair',
    dark: 'Sombre',
    system: 'Système',
    language: 'Langue',
  },
  en: {
    newChat: 'New chat',
    today: 'Today',
    days30: '30 days',
    settings: 'Settings',
    signOut: 'Sign out',
    welcomeTitle: 'Welcome to AI Advisor',
    welcomeSub: 'Your smart assistant for campaign performance, user quality, and growth decisions.',
    examples: 'Examples',
    capabilities: 'Capabilities',
    limitations: 'Limitations',
    example1: 'Which of my campaigns had the best ROI in the last 30 days?',
    example2: 'Compare retention across iOS and Android in Europe',
    example3: 'Which audience segments are dropping after Day 7?',
    cap1: 'Analyze campaign performance trends across KPIs',
    cap2: 'Recommend budget reallocations and targeting changes',
    cap3: 'Forecast LTV, retention, and ROAS for specific segments',
    limit1: 'Data must be available in your dashboard for analysis',
    limit2: 'AI suggestions are based on your data, not external sources',
    limit3: 'Always review automated recommendations before applying',
    placeholder: 'Ask anything about your campaigns, users, or performance...',
    hint: 'Enter to send · Shift+Enter for new line',
    general: 'General',
    profile: 'Profile',
    data: 'Data',
    about: 'About',
    theme: 'Theme',
    light: 'Light',
    dark: 'Dark',
    system: 'System',
    language: 'Language',
  },
  ar: {
    newChat: 'محادثة جديدة',
    today: 'اليوم',
    days30: '30 يوم',
    settings: 'الإعدادات',
    signOut: 'تسجيل الخروج',
    welcomeTitle: 'مرحبًا بك في المستشار الذكي',
    welcomeSub: 'مساعدك الذكي لأداء الحملات وجودة المستخدمين وقرارات النمو',
    examples: 'أمثلة',
    capabilities: 'القدرات',
    limitations: 'القيود',
    example1: 'ما هي الحملة التي حققت أفضل عائد على الاستثمار في آخر 30 يومًا؟',
    example2: 'قارن الاحتفاظ بين iOS و Android في أوروبا',
    example3: 'ما هي شرائح الجمهور التي تنخفض بعد اليوم السابع؟',
    cap1: 'تحليل اتجاهات أداء الحملة عبر مؤشرات الأداء الرئيسية',
    cap2: 'توصية بإعادة تخصيص الميزانية وتغييرات الاستهداف',
    cap3: 'التنبؤ بـ LTV والاحتفاظ و ROAS لشرائح محددة',
    limit1: 'يجب أن تكون البيانات متاحة في لوحة التحكم الخاصة بك للتحليل',
    limit2: 'تعتمد اقتراحات الذكاء الاصطناعي على بياناتك',
    limit3: 'راجع دائمًا التوصيات الآلية قبل التطبيق',
    placeholder: 'اسأل أي شيء عن حملاتك أو مستخدميك أو أدائك...',
    hint: 'Enter للإرسال · Shift+Enter لسطر جديد',
    general: 'عام',
    profile: 'الملف الشخصي',
    data: 'البيانات',
    about: 'حول',
    theme: 'المظهر',
    light: 'فاتح',
    dark: 'داكن',
    system: 'النظام',
    language: 'اللغة',
  },
};

export default function Chat() {
  const { user, logout } = useAuth();
  const nav = useNavigate();
  const [language, setLanguage] = useState('fr');
  const [theme, setTheme] = useState('light');
  const [showSettings, setShowSettings] = useState(false);
  const [conversations, setConversations] = useState([]);
  const [activeConvId, setActiveConvId] = useState(null);
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const messagesEndRef = useRef(null);
  const textareaRef = useRef(null);
  const t = translations[language];

  // Apply theme
  useEffect(() => {
    if (theme === 'dark') {
      document.body.classList.add('dark-theme');
    } else {
      document.body.classList.remove('dark-theme');
    }
  }, [theme]);

  useEffect(() => { loadConversations(); }, []);

  const loadConversations = async () => {
    try {
      const r = await axios.get('/conversations');
      setConversations(r.data.conversations || []);
    } catch {}
  };

  const loadConversation = async (convId) => {
    try {
      const r = await axios.get(`/conversations/${convId}/messages`);
      setMessages(r.data.messages.map(m => ({
        role: m.sender === 'user' ? 'user' : 'bot',
        content: m.content,
        timestamp: m.timestamp,
      })));
      setActiveConvId(convId);
    } catch {}
  };

  const newConversation = () => {
    setActiveConvId(null);
    setMessages([]);
    textareaRef.current?.focus();
  };

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, loading]);

  const sendMessage = useCallback(async () => {
    const text = input.trim();
    if (!text || loading) return;
    setMessages(prev => [...prev, { role: 'user', content: text, timestamp: new Date() }]);
    setInput('');
    if (textareaRef.current) textareaRef.current.style.height = 'auto';
    setLoading(true);
    try {
      const r = await axios.post('/chat', { message: text, conversation_id: activeConvId });
      setMessages(prev => [...prev, { role: 'bot', content: r.data.response, timestamp: new Date() }]);
      if (!activeConvId && r.data.conversation_id) {
        setActiveConvId(r.data.conversation_id);
        loadConversations();
      }
    } catch {
      setMessages(prev => [...prev, { role: 'bot', content: 'Error: Unable to connect to server. Please try again.', timestamp: new Date(), isError: true }]);
    } finally {
      setLoading(false);
    }
  }, [input, loading, activeConvId]);

  const handleKeyDown = e => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const handleInputChange = e => {
    setInput(e.target.value);
    const el = textareaRef.current;
    if (el) {
      el.style.height = 'auto';
      el.style.height = Math.min(el.scrollHeight, 200) + 'px';
    }
  };

  const deleteConversation = async (convId, e) => {
    e.stopPropagation();
    try {
      await axios.delete(`/conversations/${convId}`);
      if (activeConvId === convId) newConversation();
      loadConversations();
    } catch {}
  };

  // Group conversations by date
  const today = new Date().toDateString();
  const grouped = {
    today: conversations.filter(c => new Date(c.updated_at).toDateString() === today),
    days30: conversations.filter(c => {
      const diff = Math.floor((new Date() - new Date(c.updated_at)) / (1000 * 60 * 60 * 24));
      return diff > 0 && diff <= 30;
    }),
  };

  const examples = [t.example1, t.example2, t.example3];
  const capabilities = [t.cap1, t.cap2, t.cap3];
  const limitations = [t.limit1, t.limit2, t.limit3];

  return (
    <div className={s.layout}>
      {/* Settings Modal */}
      {showSettings && (
        <div className={s.modalOverlay} onClick={() => setShowSettings(false)}>
          <div className={s.modal} onClick={e => e.stopPropagation()}>
            <div className={s.modalHeader}>
              <h3>{t.settings}</h3>
              <button className={s.closeModal} onClick={() => setShowSettings(false)}>×</button>
            </div>
            <div className={s.modalBody}>
              <div className={s.settingSection}>
                <h4>{t.general}</h4>
                <div className={s.settingItem}>
                  <span>{t.theme}</span>
                  <div className={s.themeOptions}>
                    <button onClick={() => setTheme('light')} className={`${s.themeBtn} ${theme === 'light' ? s.themeActive : ''}`}>{t.light}</button>
                    <button onClick={() => setTheme('dark')} className={`${s.themeBtn} ${theme === 'dark' ? s.themeActive : ''}`}>{t.dark}</button>
                    <button onClick={() => setTheme('system')} className={`${s.themeBtn} ${theme === 'system' ? s.themeActive : ''}`}>{t.system}</button>
                  </div>
                </div>
                <div className={s.settingItem}>
                  <span>{t.language}</span>
                  <div className={s.langOptions}>
                    <button onClick={() => setLanguage('fr')} className={`${s.langOptionBtn} ${language === 'fr' ? s.langOptionActive : ''}`}>FR</button>
                    <button onClick={() => setLanguage('en')} className={`${s.langOptionBtn} ${language === 'en' ? s.langOptionActive : ''}`}>EN</button>
                    <button onClick={() => setLanguage('ar')} className={`${s.langOptionBtn} ${language === 'ar' ? s.langOptionActive : ''}`}>AR</button>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Sidebar */}
      <aside className={`${s.sidebar} ${sidebarOpen ? s.sideOpen : ''}`}>
        <div className={s.sideHeader}>
          <button className={s.newChatBtn} onClick={newConversation}>
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/>
            </svg>
            {t.newChat}
          </button>
        </div>
        <div className={s.sideContent}>
          {grouped.today.length > 0 && (
            <div className={s.dateGroup}>
              <div className={s.dateLabel}>{t.today}</div>
              {grouped.today.map(c => (
                <div key={c.id} className={`${s.convItem} ${activeConvId === c.id ? s.convActive : ''}`} onClick={() => loadConversation(c.id)}>
                  <svg className={s.convIcon} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>
                  <span className={s.convTitle}>{c.title || 'Conversation'}</span>
                  <button onClick={e => deleteConversation(c.id, e)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#8e8e93' }}>×</button>
                </div>
              ))}
            </div>
          )}
          {grouped.days30.length > 0 && (
            <div className={s.dateGroup}>
              <div className={s.dateLabel}>{t.days30}</div>
              {grouped.days30.map(c => (
                <div key={c.id} className={`${s.convItem} ${activeConvId === c.id ? s.convActive : ''}`} onClick={() => loadConversation(c.id)}>
                  <svg className={s.convIcon} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>
                  <span className={s.convTitle}>{c.title || 'Conversation'}</span>
                  <button onClick={e => deleteConversation(c.id, e)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#8e8e93' }}>×</button>
                </div>
              ))}
            </div>
          )}
        </div>
        <div className={s.sideFooter}>
          <button className={s.userBtn} onClick={() => setShowSettings(true)}>
            <div className={s.userAvatar}>{user?.username?.[0]?.toUpperCase() || 'U'}</div>
            <div className={s.userInfo}>
              <div className={s.userName}>{user?.username || 'User'}</div>
              <div className={s.userEmail}>{user?.email || ''}</div>
            </div>
          </button>
          <button className={s.userBtn} onClick={() => { logout(); nav('/'); }} style={{ marginTop: 8 }}>
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/></svg>
            <span>{t.signOut}</span>
          </button>
        </div>
      </aside>

      {/* Main Chat Area */}
      <main className={s.main}>
        <div className={s.mainHeader}>
          <div className={s.headerLeft}>
            {!sidebarOpen && <button className={s.menuBtn} onClick={() => setSidebarOpen(true)}>☰</button>}
            <div className={s.headerLogo}>
              <img src="/logo.png" alt="Logo" />
              <span>AWAL GPT</span>
            </div>
          </div>
          <div className={s.headerActions}>
            <button onClick={() => setLanguage('fr')} className={`${s.langBtn} ${language === 'fr' ? s.langActive : ''}`}>FR</button>
            <button onClick={() => setLanguage('en')} className={`${s.langBtn} ${language === 'en' ? s.langActive : ''}`}>EN</button>
            <button onClick={() => setLanguage('ar')} className={`${s.langBtn} ${language === 'ar' ? s.langActive : ''}`}>AR</button>
            <button className={s.langBtn} onClick={() => setShowSettings(true)}>⚙️</button>
          </div>
        </div>

        <div className={s.messagesArea}>
          <div className={s.messages}>
            {messages.length === 0 ? (
              <div className={s.welcome}>
                <img src="/logo.png" alt="Logo" className={s.welcomeLogo} />
                <h1 className={s.welcomeTitle}>{t.welcomeTitle}</h1>
                <p className={s.welcomeSub}>{t.welcomeSub}</p>
                <div className={s.welcomeGrid}>
                  <div className={s.welcomeCard}>
                    <h4>{t.examples}</h4>
                    {examples.map((ex, i) => <p key={i} onClick={() => setInput(ex)}>{ex}</p>)}
                  </div>
                  <div className={s.welcomeCard}>
                    <h4>{t.capabilities}</h4>
                    {capabilities.map((cap, i) => <p key={i} className={s.capability}>{cap}</p>)}
                  </div>
                  <div className={s.welcomeCard}>
                    <h4>{t.limitations}</h4>
                    {limitations.map((lim, i) => <p key={i} className={s.limitation}>{lim}</p>)}
                  </div>
                </div>
              </div>
            ) : (
              messages.map((msg, idx) => (
                <div key={idx} className={s.message}>
                  <div className={s.messageAvatar}>
                    {msg.role === 'user' ? (
                      <div className={s.userAvatarMsg}>{user?.username?.[0]?.toUpperCase() || 'U'}</div>
                    ) : (
                      <div className={s.botAvatar}>🤖</div>
                    )}
                  </div>
                  <div className={s.messageContent}>
                    <div className={s.messageName}>{msg.role === 'user' ? (user?.username || 'You') : 'AI Advisor'}</div>
                    <div className={s.messageText}>
                      {msg.content.includes('```') ? (
                        <pre><code>{msg.content.replace(/```/g, '')}</code></pre>
                      ) : (
                        msg.content
                      )}
                    </div>
                  </div>
                </div>
              ))
            )}
            {loading && (
              <div className={s.message}>
                <div className={s.messageAvatar}><div className={s.botAvatar}>🤖</div></div>
                <div className={s.messageContent}>
                  <div className={s.messageName}>AI Advisor</div>
                  <div className={s.typing}><span /><span /><span /></div>
                </div>
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>
        </div>

        <div className={s.inputArea}>
          <div className={s.inputContainer}>
            <div className={s.inputBox}>
              <textarea
                ref={textareaRef}
                className={s.textarea}
                placeholder={t.placeholder}
                value={input}
                onChange={handleInputChange}
                onKeyDown={handleKeyDown}
                rows={1}
                disabled={loading}
              />
              <button className={s.sendBtn} onClick={sendMessage} disabled={loading || !input.trim()}>
                <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/>
                </svg>
              </button>
            </div>
            <div className={s.inputHint}>{t.hint}</div>
          </div>
        </div>
      </main>
    </div>
  );
}
